export class PersistentVector<T> {
  private static readonly BITS = 5;
  private static readonly WIDTH = 1 << PersistentVector.BITS; // 32
  private static readonly MASK = PersistentVector.WIDTH - 1;

  private constructor(
    private readonly root: Node<T>,
    private readonly _size: number,
    private readonly shift: number
  ) {}

  static empty<T>(): PersistentVector<T> {
    return new PersistentVector<T>(new Node<T>(), 0, 0);
  }

  get size(): number {
    return this._size;
  }

  get(i: number): T {
    if (i < 0 || i >= this._size) {
      throw new Error("Index out of range");
    }

    let node = this.root;
    for (let level = this.shift; level > 0; level -= PersistentVector.BITS) {
      node = node.children[(i >>> level) & PersistentVector.MASK]!;
    }
    return node.children[i & PersistentVector.MASK] as unknown as T;
  }

  push(value: T): PersistentVector<T> {
    // If the root is full, we need to increase the height of the tree
    if ((this._size >>> this.shift) > PersistentVector.MASK) {
      const newRoot = new Node<T>();
      newRoot.children[0] = this.root;
      newRoot.children[1] = this.createPath(this.shift, value);
      return new PersistentVector<T>(newRoot, this._size + 1, this.shift + PersistentVector.BITS);
    }

    return new PersistentVector<T>(
      this.pushRecursive(this.shift, this.root, this._size, value),
      this._size + 1,
      this.shift
    );
  }

  private pushRecursive(level: number, node: Node<T>, index: number, value: T): Node<T> {
    const newNode = node.clone();
    if (level === 0) {
      newNode.children[index & PersistentVector.MASK] = value;
    } else {
      const subIndex = (index >>> level) & PersistentVector.MASK;
      const childNode = node.children[subIndex];

      if (childNode === undefined) {
        newNode.children[subIndex] = this.createPath(level - PersistentVector.BITS, value);
      } else {
        newNode.children[subIndex] = this.pushRecursive(level - PersistentVector.BITS, childNode as Node<T>, index, value);
      }
    }
    return newNode;
  }

  private createPath(level: number, value: T): Node<T> {
    const node = new Node<T>();
    if (level === 0) {
      node.children[0] = value;
    } else {
      node.children[0] = this.createPath(level - PersistentVector.BITS, value);
    }
    return node;
  }
}

class Node<T> {
  // Using an array to store either child Nodes or the actual values T at the leaf level
  children: unknown[] = new Array(PersistentVector.WIDTH);

  clone(): Node<T> {
    const newNode = new Node<T>();
    newNode.children = [...this.children];
    return newNode;
  }
}

